<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bouncing Ball Playground</title>
<style>
  :root {
    color-scheme: dark;
  }
  html, body {
    margin: 0;
    padding: 0;
    height: 100%;
    background: #12141c;
    color: #e6e6f0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 16px;
  }
  h1 {
    font-size: 1.1rem;
    font-weight: 500;
    letter-spacing: 0.03em;
    color: #9aa0c0;
    margin: 0;
  }
  #stage {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 14px;
    padding: 20px;
    border-radius: 16px;
    background: linear-gradient(180deg, #1a1d29, #14161f);
    box-shadow: 0 20px 50px rgba(0,0,0,0.5), inset 0 0 0 1px #262a3a;
  }
  #sim {
    width: 480px;
    height: 480px;
    border-radius: 10px;
    background: radial-gradient(circle at 50% 30%, #1c1f30, #0d0e14);
    box-shadow: inset 0 0 0 1px #2c3040, inset 0 0 30px rgba(0,0,0,0.6);
    cursor: crosshair;
    display: block;
  }
  #controls {
    display: flex;
    gap: 10px;
  }
  button {
    background: #232636;
    color: #dcdfec;
    border: 1px solid #333750;
    border-radius: 8px;
    padding: 8px 18px;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s ease, transform 0.05s ease;
  }
  button:hover {
    background: #2c3049;
  }
  button:active {
    transform: scale(0.96);
  }
  #play.paused {
    background: #3a2c2c;
    border-color: #5a3a3a;
  }
  #hint {
    color: #666b85;
    font-size: 0.78rem;
  }
</style>
</head>
<body>
  <h1>Bouncing Ball Playground</h1>
  <div id="stage">
    <canvas id="sim" width="480" height="480"></canvas>
    <div id="controls">
      <button id="drop">Drop Ball</button>
      <button id="play">Pause</button>
      <button id="clear">Clear</button>
    </div>
    <div id="hint">Click the canvas to drop a ball at the cursor</div>
  </div>

<script>
(function() {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.5;
  const RESTITUTION = 0.78;
  const COLORS = ['#ff6b6b', '#4ecdc4', '#ffe66d', '#a78bfa', '#5fd2ff', '#ff9f5b', '#7ee787'];

  let balls = [];
  let running = true;
  let colorIdx = 0;

  function makeBall(x, y, vx, vy, r) {
    r = r || (10 + Math.random() * 14);
    const b = {
      x: clamp(x, r, W - r),
      y: clamp(y, r, H - r),
      vx: vx || 0,
      vy: vy || 0,
      r: r,
      color: COLORS[colorIdx % COLORS.length]
    };
    colorIdx++;
    return b;
  }

  function clamp(v, lo, hi) {
    return Math.max(lo, Math.min(hi, v));
  }

  function addBall(x, y, vx, vy, r) {
    const b = makeBall(x, y, vx, vy, r);
    balls.push(b);
    draw();
    return b;
  }

  function clearBalls() {
    balls = [];
    draw();
  }

  function step(dt) {
    dt = dt === undefined ? 1 : dt;
    for (const b of balls) {
      b.vy += GRAVITY * dt;
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      if (b.x - b.r < 0) {
        b.x = b.r;
        b.vx = -b.vx * RESTITUTION;
      } else if (b.x + b.r > W) {
        b.x = W - b.r;
        b.vx = -b.vx * RESTITUTION;
      }

      if (b.y - b.r < 0) {
        b.y = b.r;
        b.vy = -b.vy * RESTITUTION;
      } else if (b.y + b.r > H) {
        b.y = H - b.r;
        b.vy = -b.vy * RESTITUTION;
      }
    }
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);

    ctx.strokeStyle = 'rgba(255,255,255,0.04)';
    ctx.lineWidth = 1;
    for (let x = 0; x <= W; x += 40) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, H);
      ctx.stroke();
    }
    for (let y = 0; y <= H; y += 40) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(W, y);
      ctx.stroke();
    }

    for (const b of balls) {
      const grad = ctx.createRadialGradient(
        b.x - b.r * 0.35, b.y - b.r * 0.35, b.r * 0.1,
        b.x, b.y, b.r
      );
      grad.addColorStop(0, '#ffffff');
      grad.addColorStop(0.25, b.color);
      grad.addColorStop(1, shade(b.color, -30));

      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();

      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.strokeStyle = 'rgba(0,0,0,0.3)';
      ctx.lineWidth = 1;
      ctx.stroke();
    }
  }

  function shade(hex, percent) {
    const num = parseInt(hex.slice(1), 16);
    let r = (num >> 16) + percent;
    let g = ((num >> 8) & 0x00FF) + percent;
    let b = (num & 0x0000FF) + percent;
    r = clamp(r, 0, 255);
    g = clamp(g, 0, 255);
    b = clamp(b, 0, 255);
    return '#' + (0x1000000 + r * 0x10000 + g * 0x100 + b).toString(16).slice(1);
  }

  let rafId = null;
  function loop() {
    if (!running) return;
    step(1);
    rafId = requestAnimationFrame(loop);
  }

  function startLoop() {
    if (rafId === null) {
      running = true;
      rafId = requestAnimationFrame(loop);
    }
  }

  function stopLoop() {
    running = false;
    if (rafId !== null) {
      cancelAnimationFrame(rafId);
      rafId = null;
    }
  }

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    addBall(x, y, (Math.random() - 0.5) * 6, -Math.random() * 4);
  });

  document.getElementById('drop').addEventListener('click', () => {
    const x = W / 2 + (Math.random() - 0.5) * (W * 0.4);
    addBall(x, 40, (Math.random() - 0.5) * 8, 0);
  });

  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', () => {
    if (running) {
      stopLoop();
      playBtn.textContent = 'Play';
      playBtn.classList.add('paused');
    } else {
      startLoop();
      playBtn.textContent = 'Pause';
      playBtn.classList.remove('paused');
    }
  });

  document.getElementById('clear').addEventListener('click', () => {
    clearBalls();
  });

  addBall(W * 0.3, H * 0.2, 3, 0);
  addBall(W * 0.7, H * 0.15, -2, 0, 18);

  startLoop();

  window.sim = {
    w: W,
    h: H,
    balls: function() {
      return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
    },
    addBall: function(x, y, vx, vy, r) {
      addBall(x, y, vx, vy, r);
    },
    clear: function() {
      clearBalls();
    },
    step: function(dt) {
      step(dt === undefined ? 1 : dt);
    }
  };

  draw();
})();
</script>
</body>
</html>
